To build this DCTL, you must sequence three operations: 1) ARRI LogC4 to Scene Linear, 2) AWG4 to AP1 matrix transform, and 3) Scene Linear to ACEScct. First, the LogC4 to linear curve requires reversing the ARRI formula: `Linear = (pow(2.0f, (14.0f * LogC4 - 0.052272f) / 0.243542f) - 0.041634f) / 64.0f`. Next, apply the 3x3 matrix to convert from ARRI Wide Gamut 4 (AWG4) to ACES AP1. The matrix (derived from AWG4 primaries to AP1 primaries via XYZ) is approximately: 
`float3x3 awg4_to_ap1 = {
  0.8654f, 0.0385f, 0.0961f,
  0.0210f, 0.9930f, -0.0140f,
  0.0003f, -0.0101f, 1.0098f 
};`. Finally, convert the new AP1 linear values to ACEScct using the piecewise function: `if (lin > 0.0078125f) { ACEScct = (log2f(lin) + 9.72f) / 17.52f; } else { ACEScct = 10.54f * lin + 0.0729055341958355f; }`. You multiply the linearized RGB vector by the `awg4_to_ap1` matrix using `make_float3` and apply the ACEScct log encoding to the result.

```javascript
(function() {
    var proj = app.project;
    if (!proj) return alert('No project open.');

    var exportPath = '~/Desktop/XML_Exports/';
    var folder = new Folder(exportPath);
    if (!folder.exists) folder.create();

    function findBinByName(root, name) {
        for (var i = 0; i < root.children.numItems; i++) {
            var item = root.children[i];
            if (item.type === ProjectItemType.BIN && item.name === name) return item;
            if (item.type === ProjectItemType.BIN) {
                var found = findBinByName(item, name);
                if (found) return found;
            }
        }
        return null;
    }

    var reelsBin = findBinByName(proj.rootItem, 'Reels');
    if (!reelsBin) return alert('Bin "Reels" not found.');

    for (var j = 0; j < reelsBin.children.numItems; j++) {
        var seqItem = reelsBin.children[j];
        if (seqItem.type !== ProjectItemType.CLIP && seqItem.isSequence()) {
            var seq = seqItem.getSequence();
            proj.activeSequence = seq;

            // Disable all video tracks
            for (var v = 0; v < seq.videoTracks.numTracks; v++) {
                seq.videoTracks[v].setMute(1);
            }

            // Mute all audio tracks first, then unmute 1-4
            for (var a = 0; a < seq.audioTracks.numTracks; a++) {
                seq.audioTracks[a].setMute(1);
            }

            try {
                var maxTracks = Math.min(seq.audioTracks.numTracks, 4);
                for (var t = 0; t < maxTracks; t++) {
                    seq.audioTracks[t].setMute(0);
                }
            } catch(e) {
                $.writeln('Error modifying audio tracks for: ' + seq.name);
            }

            var xmlOutPath = exportPath + seq.name + '.xml';
            proj.exportAsFinalCutProXML(xmlOutPath, 1); // 1 = suppress UI
        }
    }
    alert('XML Export Complete.');
})();
```
